"""
Belief-state replay: reconstruct what the store would expose as of a past cutoff.

Honesty constraints:
- Embedding vectors and cluster IDs reflect the *current* encoder and graph; replay
  filters *which* claims/conclusions participate by effective time, not historical weights.
- Use ``embedding_model_version`` rows to surface which encoder was pinned when; if the
  table only has the auto-seed row, callers should warn that encoder drift is unmodeled.
"""

from __future__ import annotations

import hashlib
import json
from dataclasses import dataclass, field
from datetime import date, datetime, time, timezone
from typing import Any, Iterable, Optional

from noosphere.models import Artifact, Claim, Conclusion
from noosphere.observability import get_logger
from noosphere.store import Store, StoredEmbeddingModelVersion

logger = get_logger(__name__)


def parse_cutoff_date(s: str) -> date:
    return date.fromisoformat(s.strip())


def cutoff_datetime_inclusive_utc(d: date) -> datetime:
    """Inclusive end-of-calendar-day UTC for ``effective_at <= cutoff`` checks."""
    return datetime(d.year, d.month, d.day, 23, 59, 59, tzinfo=timezone.utc)


def _ensure_utc(dt: datetime) -> datetime:
    if dt.tzinfo is None:
        return dt.replace(tzinfo=timezone.utc)
    return dt.astimezone(timezone.utc)


def effective_datetime_for_artifact(art: Artifact) -> tuple[datetime, bool]:
    if art.effective_at is not None:
        return _ensure_utc(art.effective_at), art.effective_at_inferred
    if art.source_date:
        d = art.source_date
        return (
            datetime(d.year, d.month, d.day, 23, 59, 59, tzinfo=timezone.utc),
            False,
        )
    return _ensure_utc(art.created_at), True


def effective_datetime_for_claim(store: Store, c: Claim) -> tuple[datetime, bool]:
    if c.effective_at is not None:
        return _ensure_utc(c.effective_at), c.effective_at_inferred
    if c.source_id:
        art = store.get_artifact(c.source_id)
        if art is not None:
            return effective_datetime_for_artifact(art)
    return datetime.combine(c.episode_date, time.max, tzinfo=timezone.utc), True


def is_active_superseded(superseded_at: Optional[datetime], cutoff: datetime) -> bool:
    if superseded_at is None:
        return True
    return _ensure_utc(superseded_at) > cutoff


def claim_visible_as_of(store: Store, c: Claim, cutoff: datetime) -> bool:
    if not is_active_superseded(c.superseded_at, cutoff):
        return False
    eff, _ = effective_datetime_for_claim(store, c)
    return eff <= cutoff


def artifact_visible_as_of(store: Store, artifact_id: str, cutoff: datetime) -> bool:
    if not artifact_id:
        return True
    art = store.get_artifact(artifact_id)
    if art is None:

def insert_cascade_node(self, node: CascadeNode) -> None:
    row = StoredCascadeNode(
        node_id=node.node_id,
        kind=node.kind.value,
        payload_json=node.model_dump_json(),
    )
    with self.session() as s:
        s.add(row)
        s.commit()

def get_cascade_node(self, node_id: str) -> Optional[CascadeNode]:
    with self.session() as s:
        r = s.get(StoredCascadeNode, node_id)
        if r is None:
            return None
        return CascadeNode.model_validate_json(r.payload_json)

def insert_cascade_edge(self, edge: CascadeEdge) -> None:
    with self.session() as s:
        inv = s.get(StoredMethodInvocation, edge.method_invocation_id)
        if inv is None:
            raise CascadeEdgeOrphanError(
                f"method_invocation_id {edge.method_invocation_id!r} not found"
            )
        if edge.relation in (
            CascadeEdgeRelation.SUPPORTS,
            CascadeEdgeRelation.REFUTES,
        ):
            opposite = (
                CascadeEdgeRelation.REFUTES
                if edge.relation == CascadeEdgeRelation.SUPPORTS
                else CascadeEdgeRelation.SUPPORTS
            )
            conflict = s.exec(
                select(StoredCascadeEdge).where(
                    StoredCascadeEdge.src == edge.src,
                    StoredCascadeEdge.dst == edge.dst,
                    StoredCascadeEdge.relation == opposite.value,
                    StoredCascadeEdge.retracted_at == None,  # noqa: E711
                )
            ).first()
            if conflict is not None:
                raise CascadeEdgeConflictError(
                    f"Non-retracted {opposite.value} edge exists "
                    f"between {edge.src} -> {edge.dst}"
                )
        row = StoredCascadeEdge(
            edge_id=edge.edge_id,
            src=edge.src,
            dst=edge.dst,
            relation=edge.relation.value,
            method_invocation_id=edge.method_invocation_id,
            retracted_at=edge.retracted_at,
            payload_json=edge.model_dump_json(),
        )
        s.add(row)
        s.commit()

def retract_cascade_edge(self, edge_id: str, retracted_at: datetime) -> None:
    with self.session() as s:
        r = s.get(StoredCascadeEdge, edge_id)
        if r is None:
            return
        r.retracted_at = retracted_at
        edge = CascadeEdge.model_validate_json(r.payload_json)
        edge.retracted_at = retracted_at
        r.payload_json = edge.model_dump_json()
        s.add(r)
        s.commit()

def iter_cascade_edges(
    self,
    src: Optional[str] = None,
    dst: Optional[str] = None,
    relation: Optional[str] = None,
    include_retracted: bool = False,
) -> Iterator[CascadeEdge]:
    with self.session() as s:
        stmt = select(StoredCascadeEdge)
        if src is not None:
            stmt = stmt.where(StoredCascadeEdge.src == src)
        if dst is not None:
            stmt = stmt.where(StoredCascadeEdge.dst == dst)
        if relation is not None:
            stmt = stmt.where(StoredCascadeEdge.relation == relation)
        if not include_retracted:
            stmt = stmt.where(StoredCascadeEdge.retracted_at == None)  # noqa: E711
        rows = s.exec(stmt).all()
    for r in rows:
        yield CascadeEdge.model_validate_json(r.payload_json)

# ── Round 3: Temporal cuts / Evaluation ───────────────────────────────

def insert_temporal_cut(self, cut: TemporalCut) -> None:
    row = StoredTemporalCut(cut_id=cut.cut_id, payload_json=cut.model_dump_json())
    with self.session() as s:
        s.add(row)
        for outcome in cut.outcomes:
            if not s.get(StoredOutcome, outcome.outcome_id):
                s.add(
                    StoredOutcome(
                        outcome_id=outcome.outcome_id,
                        payload_json=outcome.model_dump_json(),
                    )
                )
            assoc_id = f"{cut.cut_id}:{outcome.outcome_id}"
            if not s.get(StoredCutOutcome, assoc_id):
                s.add(
                    StoredCutOutcome(
                        id=assoc_id,
                        cut_id=cut.cut_id,
                        outcome_id=outcome.outcome_id,
                    )
                )
        s.commit()

